const item = $('Normalise Payload').first().json;

function sanitiseForPrompt(text) {
  if (!text) return '';
  return String(text)
    .replace(/<[^>]*>/g, '')
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '')
    .replace(/\{\{[\s\S]*?\}\}/g, '[TEMPLATE_REMOVED]')
    .replace(/\bignore\s+(?:all\s+)?previous\s+instructions?\b/gi, '[INJECTION_ATTEMPT]')
    .substring(0, 4000)
    .trim();
}

function sqlEsc(v) {
  return String(v == null ? '' : v).replace(/'/g, "''").replace(/\x00/g, '');
}

return [{
  json: {
    gmail_message_id: item.gmail_message_id || item.id || '',
    account:          item.account || 'jolyon.sandercock@gmail.com',
    from_address:     item.from?.value?.[0]?.address || item.from_address || '',
    from_name:        item.from?.value?.[0]?.name    || item.from_name    || '',
    subject:          item.subject  || '',
    body_text:        item.text     || item.body_text || '',
    received_at:      item.date     || item.received_at || new Date().toISOString(),
    has_attachment:   !!(item.attachments && item.attachments.length > 0) || !!item.has_attachment,
    body_text_safe:   sanitiseForPrompt(item.text || item.body_text || ''),
    sql_gmail_message_id: sqlEsc(item.gmail_message_id || item.id || ''),
    sql_account:      sqlEsc(item.account || 'jolyon.sandercock@gmail.com'),
    sql_from_address: sqlEsc(item.from?.value?.[0]?.address || item.from_address || ''),
    sql_from_name:    sqlEsc(item.from?.value?.[0]?.name    || item.from_name    || ''),
    sql_subject:      sqlEsc(item.subject || ''),
    sql_body_text:    sqlEsc(item.text || item.body_text || ''),
    sql_received_at:  sqlEsc(item.date || item.received_at || new Date().toISOString()),
  }
}];

const item = $input.first().json;
const threshRow = $('Fetch AI Thresholds').first().json;
const thresholds = typeof threshRow.value === 'string'
  ? JSON.parse(threshRow.value)
  : threshRow.value;
const minConf = thresholds?.email_classifier?.min_confidence ?? 0.80;

let ai;
try {
  ai = JSON.parse(item.response || '{}');
} catch(e) {
  ai = { category: 'fyi', entity_id: 3, confidence_score: 1.0,
         summary: 'Parse error — defaulted to fyi', requires_human: true };
}

const validCats = ['invoice','action-required','report-attachment',
                   'school-medical','property','pub','fyi','junk'];
const category   = validCats.includes(ai.category) ? ai.category : 'fyi';
const entityId   = [1,2,3,4].includes(Number(ai.entity_id)) ? Number(ai.entity_id) : 3;
const confidence = Math.min(1, Math.max(0, Number(ai.confidence_score) || 0));
const summary    = String(ai.summary || '').substring(0, 500);



// OUTCOME_PATCH_v1
const status = confidence >= minConf
  ? 'success'
  : confidence >= minConf * 0.85
    ? 'escalate'
    : 'fail';

const outcome = {
  status,
  confidence,
  reasoning:    String(ai.reasoning || ai.summary || '').substring(0, 1000),
  data:         { category, entity_id: entityId, summary,
                  requires_human: !!ai.requires_human },
  requires_human: status === 'fail' || !!ai.requires_human || confidence < minConf,
  worker:       'email_classifier',
  tier_used:    'hot'
};

const emailData = $('Sanitise Email').first().json;
return [{
  json: {
    ...emailData,
    ai_category:      category,
    ai_entity_id:     entityId,
    ai_confidence:    confidence,
    ai_summary:       summary,
    ai_requires_human: !!ai.requires_human || confidence < minConf,
    ai_worker:        'email_classifier',
    ai_model:         'qwen2.5:7b',
    ai_raw_output:    JSON.stringify(ai),
    needs_escalation: confidence < minConf,
    email_threshold:  minConf,
    outcome,
  }
}];

const item = $input.first().json;
const vaultResp = $('Fetch Anthropic Key').first().json;
const anthropicKey = vaultResp.data?.data?.api_key || '';

let ai;
try {
  const text = item.content?.[0]?.text || '{}';
  ai = JSON.parse(text);
} catch(e) {
  ai = { category: 'fyi', entity_id: 3, confidence_score: 1.0,
         summary: 'Haiku parse error — defaulted to fyi', requires_human: true };
}

const validCats = ['invoice','action-required','report-attachment',
                   'school-medical','property','pub','fyi','junk'];
const category   = validCats.includes(ai.category) ? ai.category : 'fyi';
const entityId   = [1,2,3,4].includes(Number(ai.entity_id)) ? Number(ai.entity_id) : 3;
const confidence = Math.min(1, Math.max(0, Number(ai.confidence_score) || 0));
const summary    = String(ai.summary || '').substring(0, 500);

const emailData = $('Sanitise Email').first().json;
const threshold = $('Parse Ollama Response').first().json.email_threshold || 0.80;

// OUTCOME_PATCH_v1
const status = confidence >= threshold
  ? 'success'
  : confidence >= threshold * 0.85
    ? 'escalate'
    : 'fail';

const outcome = {
  status,
  confidence,
  reasoning:    String(ai.reasoning || ai.summary || '').substring(0, 1000),
  data:         { category, entity_id: entityId, summary,
                  requires_human: !!ai.requires_human },
  requires_human: status === 'fail' || !!ai.requires_human || confidence < threshold,
  worker:       'email_classifier',
  tier_used:    'haiku'
};

return [{
  json: {
    ...emailData,
    ai_category:      category,
    ai_entity_id:     entityId,
    ai_confidence:    confidence,
    ai_summary:       summary,
    ai_requires_human: !!ai.requires_human || confidence < threshold,
    ai_worker:        'email_classifier',
    ai_model:         'claude-haiku-4-5-20251001',
    ai_raw_output:    JSON.stringify(ai),
    needs_escalation: false,
    email_threshold:  threshold,
    outcome,
  }
}];

// INSERT RETURNING gives the row; SET/RESET give empty results.
// n8n returns the last non-empty result from allowMultipleStatements.
const rows = $input.all();
const row = rows.find(r => r.json.id != null) || rows[0];
const emailData = $('Sanitise Email').first().json;
const aiData = $('Merge AI Output').first().json;
return [{ json: { ...emailData, ...aiData, email_db_id: row?.json?.id, trace_id: row?.json?.trace_id || null } }];

const crypto = require('crypto');
const item = $input.first().json;
const signingKey = $('Fetch Vault Keys').first().json.data.data.payload_hmac_key;
const traceId = crypto.randomUUID();
const emailId = item.email_db_id;
const gmailId = item.gmail_message_id;

function sign(payload) {
  const s = JSON.stringify(payload);
  return 'hmac-sha256:' + crypto.createHmac('sha256', signingKey).update(s).digest('hex');
}

const rcvd = { gmail_message_id: gmailId, email_id: emailId,
  from_address: item.from_address, subject: item.subject,
  has_attachment: item.has_attachment, received_at: item.received_at };

const clsf = { gmail_message_id: gmailId, email_id: emailId,
  category: item.ai_category, entity_id: item.ai_entity_id,
  confidence_score: item.ai_confidence, summary: item.ai_summary,
  requires_human: item.ai_requires_human,
  ai_worker: item.ai_worker, model_used: item.ai_model };

const inv = { gmail_message_id: gmailId, email_id: emailId,
  source: 'email', entity_id: item.ai_entity_id };

const child = { gmail_message_id: gmailId, email_id: emailId,
  source: 'email', entity_id: item.ai_entity_id,
  from_address: item.from_address, subject: item.subject,
  body_text_safe: item.body_text_safe || '',
  classification: item.ai_category,
  ai_summary: item.ai_summary,
  detected_at: new Date().toISOString() };



// OUTCOME_PATCH_v1
const outcome_json = JSON.stringify(item.outcome || {});

return [{
  json: {
    ...item,
    trace_id: traceId,
    rcvd_payload:   JSON.stringify(rcvd),  rcvd_sig:  sign(rcvd),
    clsf_payload:   JSON.stringify(clsf),  clsf_sig:  sign(clsf),
    inv_payload:    JSON.stringify(inv),   inv_sig:   sign(inv),
    child_payload:  JSON.stringify(child), child_sig: sign(child),  // CHILD_EVENT_PATCH_v1
    idem_email:     'email_' + gmailId,
    idem_classified:'email_classified_' + gmailId,
    idem_invoice:   'invoice_from_email_' + gmailId,
    idem_child:     'child_event_from_email_' + gmailId,
    outcome_json,
  }
}];

// Webhook wraps POST body under .body; flatten it once.
// Then merge the events.payload JSONB to top level so downstream nodes
// see gmail_message_id/from_address/subject/body_text without descending
// into .payload — matches what Sanitise Email expects.
const raw = $input.first().json;
const eventRow = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const eventPayload = (eventRow.payload && typeof eventRow.payload === 'object') ? eventRow.payload : {};
return [{ json: { ...eventRow, ...eventPayload } }];
